def generateParenthesis(self, n: int) -> list[str]:
    ans, path = [], []

    def bt(left, right):
        if not left and not right:
            ans.append("".join(path))
            return
        if left > 0:
            path.append("(")
            bt(left - 1, right)
            path.pop()
        if right > left:
            path.append(")")
            bt(left, right - 1)
            path.pop()

    bt(n, n)
    return ans
